        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className="block text-xs uppercase tracking-widest text-stone-500 mb-2">Correo Electrónico</label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full p-3 border border-stone-300 focus:border-stone-900 focus:ring-0 transition-colors font-mono text-sm bg-stone-50"
              placeholder="usuario@udea.edu.co"
              autoFocus
            />
          </div>

          {error && (
            <div className="text-red-600 text-xs flex items-center gap-2">
              <AlertCircle size={12} />
              {error}
            </div>
          )}

          <button
            type="submit"
            className="w-full bg-stone-900 text-white py-3 px-4 hover:bg-stone-800 transition-colors uppercase tracking-widest text-xs font-semibold"
