const EvaluationForm: React.FC<{ rubric: RubricCategory[]; user: User; onCancel: () => void }> = ({ rubric, user, onCancel }) => {
  const [studentName, setStudentName] = useState('');
  const [evaluations, setEvaluations] = useState<Record<string, { score: number; weight: number; comment: string }>>({});

  // Initialize default weights (min value)
  useEffect(() => {
    const init: Record<string, any> = {};
    rubric.forEach(cat => {
      cat.items.forEach(item => {
        init[item.id] = { score: 0, weight: item.minWeightConfig, comment: '' };
      });
    });
    setEvaluations(init);
  }, [rubric]);

  const updateEval = (itemId: string, field: string, value: any) => {
    setEvaluations(prev => ({
      ...prev,
      [itemId]: {
        ...prev[itemId],
        [field]: value
      }
    }));
  };

  const calculateTotalWeight = () => {
    return Object.values(evaluations).reduce((sum, item) => sum + (item.weight || 0), 0);
  };

  const totalWeight = calculateTotalWeight();
  const isValidTotal = Math.abs(totalWeight - 100) < 0.1;

  const handleSave = () => {
    if (!studentName) {
      alert('Por favor ingrese el nombre del estudiante');
      return;
    }
    if (!isValidTotal) {
      alert(`La ponderación total debe ser 100%. Actual: ${totalWeight.toFixed(1)}%`);
      return;
    }

    // Calculate final weighted score (0-5 scale)
    let totalScore = 0;
    Object.keys(evaluations).forEach(key => {
        const item = evaluations[key];
        // weight is percentage, e.g. 20. So (score * 20) / 100
        totalScore += (item.score * item.weight) / 100;
    });

    const newEvaluation: Evaluation = {
      id: Date.now().toString(),
      studentName,
      evaluatorEmail: user.email,
      date: new Date().toISOString(),
      items: evaluations,
      finalScore: totalScore,
      totalWeight
    };

    StorageService.saveEvaluation(newEvaluation);
    alert('Evaluación guardada exitosamente');
    onCancel();
  };

  return (
    <div className="max-w-5xl mx-auto px-4 py-8 pb-32">
      <div className="flex justify-between items-center mb-8 border-b border-stone-900 pb-4">
        <h2 className="font-serif text-3xl">Nueva Evaluación</h2>
        <div className={`text-sm px-4 py-2 font-mono ${isValidTotal ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}>
          Peso Total: {totalWeight.toFixed(1)}% / 100%
        </div>
      </div>

      <div className="mb-8">
        <label className="block text-xs uppercase tracking-widest text-stone-500 mb-2">Nombre del Estudiante</label>
        <input
          type="text"
          value={studentName}
          onChange={(e) => setStudentName(e.target.value)}
          className="w-full text-xl p-3 border-b-2 border-stone-200 focus:border-stone-900 focus:outline-none transition-colors font-serif bg-transparent"
          placeholder="Nombre Completo"
        />
      </div>

      <div className="space-y-12">
        {rubric.map(cat => (
          <div key={cat.id}>
            <div className="sticky top-16 bg-white/95 backdrop-blur z-20 py-4 border-b border-stone-100 mb-6">
              <h3 className="font-serif text-2xl text-stone-900">{cat.title}</h3>
              <p className="text-stone-500 text-sm font-light">{cat.description}</p>
            </div>

            <div className="space-y-8 pl-4 border-l-2 border-stone-100">
              {cat.items.map(item => {
                const currentEval = evaluations[item.id] || { score: 0, weight: item.minWeightConfig, comment: '' };
                const currentLevelDesc = item.levels.find(l => l.score === currentEval.score)?.description;

                return (
                  <div key={item.id} className="relative group">
                    <div className="flex flex-col md:flex-row md:items-start justify-between gap-6 mb-4">
                      <div className="flex-1">
                        <h4 className="font-medium text-lg mb-2">{item.title}</h4>
                        <div className="bg-stone-50 p-4 border border-stone-100 min-h-[80px]">
                          <span className="text-xs font-bold text-stone-400 block mb-1">NIVEL {currentEval.score}</span>
                          <p className="text-sm text-stone-700 italic">{currentLevelDesc}</p>
                        </div>
                      </div>

                      <div className="w-full md:w-64 space-y-4">
                        <div className="bg-white border border-stone-200 p-4">
                           <label className="flex justify-between text-xs text-stone-400 mb-2">
                             <span>Peso ({item.minWeightConfig}% - {item.maxWeightConfig}%)</span>
                             <span className="font-mono text-stone-900 font-bold">{currentEval.weight}%</span>
                           </label>
                           <input 
                              type="range"
                              min={item.minWeightConfig}
                              max={item.maxWeightConfig}
                              step={1}
                              value={currentEval.weight}
                              onChange={(e) => updateEval(item.id, 'weight', parseInt(e.target.value))}
                              className="w-full h-1 bg-stone-200 rounded-none appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-3 [&::-webkit-slider-thumb]:h-3 [&::-webkit-slider-thumb]:bg-stone-900"
                           />
                        </div>

                        <div>
                           <label className="block text-xs text-stone-400 mb-2">Calificación (0-5)</label>
                           <div className="flex border border-stone-200">
                             {[0,1,2,3,4,5].map(score => (
                               <button
                                 key={score}
                                 onClick={() => updateEval(item.id, 'score', score)}
                                 className={`flex-1 py-2 text-sm font-mono transition-colors ${currentEval.score === score ? 'bg-stone-900 text-white' : 'hover:bg-stone-100 text-stone-600'}`}
                               >
                                 {score}
                               </button>
                             ))}
                           </div>
                        </div>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ))}
      </div>

      <div className="fixed bottom-0 left-0 w-full bg-white border-t border-stone-200 p-4 z-50 flex justify-end gap-4 shadow-2xl">
        <button onClick={onCancel} className="px-6 py-3 text-sm uppercase tracking-widest hover:text-red-600 transition-colors">
          Cancelar
        </button>
        <button 
          onClick={handleSave}
          className={`px-8 py-3 text-sm uppercase tracking-widest text-white transition-colors ${isValidTotal ? 'bg-stone-900 hover:bg-stone-800' : 'bg-stone-300 cursor-not-allowed'}`}
          disabled={!isValidTotal}
        >
          Guardar Evaluación
        </button>
      </div>
    </div>
  );
};

