                  <td className="py-4 font-mono text-sm">{u.email}</td>
                  <td className="py-4 text-sm">
                    <span className={`px-2 py-1 text-xs ${u.role === UserRole.ADMIN ? 'bg-stone-900 text-white' : 'bg-stone-100 text-stone-600'}`}>
