type LoginStep = 'EMAIL' | 'SET_PASSWORD' | 'ENTER_PASSWORD' | 'EMAIL_SENT';

const LoginView: React.FC<{ onLogin: (user: User) => void }> = ({ onLogin }) => {
  const [step, setStep] = useState<LoginStep>('EMAIL');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [error, setError] = useState('');
  const [tempUser, setTempUser] = useState<User | null>(null);

  const handleEmailSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!email.includes('@')) {
      setError('Por favor ingrese un correo válido');
      return;
    }

    const users = StorageService.getUsers();
    const foundUser = users.find(u => u.email.toLowerCase() === email.toLowerCase());

    if (foundUser) {
      setTempUser(foundUser);
      if (foundUser.password && foundUser.isVerified) {
        setStep('ENTER_PASSWORD');
      } else {
        setStep('SET_PASSWORD');
      }
      setError('');
    } else {
      setError('Usuario no encontrado. Contacte al administrador.');
    }
  };

  const handleSetPassword = (e: React.FormEvent) => {
    e.preventDefault();
    if (password.length < 6) {
      setError('La contraseña debe tener al menos 6 caracteres.');
      return;
    }
    if (password !== confirmPassword) {
      setError('Las contraseñas no coinciden.');
      return;
    }

    setStep('EMAIL_SENT');
    setError('');
  };

  const handleLoginSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (tempUser && tempUser.password === password) {
      onLogin(tempUser);
    } else {
      setError('Contraseña incorrecta.');
    }
  };

  const simulateEmailVerification = () => {
    if (tempUser) {
      // Update user in storage
      const users = StorageService.getUsers();
      const updatedUsers = users.map(u => {
        if (u.email === tempUser.email) {
          return { ...u, password: password, isVerified: true };
        }
        return u;
      });
      StorageService.saveUsers(updatedUsers);

      // Get the updated user object
      const updatedUser = updatedUsers.find(u => u.email === tempUser.email);
      if (updatedUser) {
        onLogin(updatedUser);
      }
    }
  };

  return (
    <div className="min-h-[calc(100vh-64px)] flex items-center justify-center bg-stone-50">
      <div className="w-full max-w-md p-8 bg-white border border-stone-200 shadow-xl">
        <div className="mb-8 text-center">
          <div className="w-12 h-12 bg-stone-900 mx-auto mb-4 flex items-center justify-center text-white">
            {step === 'EMAIL_SENT' ? <Mail size={24} /> : <div className="w-6 h-6 bg-white"></div>}
          </div>
          <h2 className="font-serif text-3xl text-stone-900">
            {step === 'EMAIL' && 'Acceso'}
            {step === 'SET_PASSWORD' && 'Configurar Cuenta'}
            {step === 'ENTER_PASSWORD' && 'Bienvenido'}
            {step === 'EMAIL_SENT' && 'Verifique su Correo'}
          </h2>
          <p className="text-stone-500 mt-2 font-light text-sm">
            {step === 'EMAIL' && 'Ingrese su correo electrónico registrado.'}
            {step === 'SET_PASSWORD' && 'Esta es su primera vez. Configure una contraseña segura.'}
            {step === 'ENTER_PASSWORD' && `Ingrese su contraseña para ${email}`}
            {step === 'EMAIL_SENT' && `Hemos enviado un enlace de confirmación a ${email}`}
          </p>
        </div>

        {step === 'EMAIL' && (
          <form onSubmit={handleEmailSubmit} className="space-y-6">
            <div>
              <label className="block text-xs uppercase tracking-widest text-stone-500 mb-2">Correo Electrónico</label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full p-3 border border-stone-300 focus:border-stone-900 focus:ring-0 transition-colors font-mono text-sm bg-stone-50"
                placeholder="simon.castano@udea.edu.co"
                autoFocus
              />
            </div>
            {error && <div className="text-red-600 text-xs flex items-center gap-2"><AlertCircle size={12} />{error}</div>}
            <button type="submit" className="w-full bg-stone-900 text-white py-3 px-4 hover:bg-stone-800 transition-colors uppercase tracking-widest text-xs font-semibold flex justify-center items-center gap-2">
              Continuar <ArrowRight size={14} />
            </button>
          </form>
        )}

        {step === 'SET_PASSWORD' && (
          <form onSubmit={handleSetPassword} className="space-y-6">
            <div>
              <label className="block text-xs uppercase tracking-widest text-stone-500 mb-2">Nueva Contraseña</label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full p-3 border border-stone-300 focus:border-stone-900 focus:ring-0 transition-colors font-mono text-sm bg-stone-50"
                placeholder="••••••••"
                autoFocus
              />
            </div>
            <div>
              <label className="block text-xs uppercase tracking-widest text-stone-500 mb-2">Confirmar Contraseña</label>
              <input
                type="password"
                value={confirmPassword}
                onChange={(e) => setConfirmPassword(e.target.value)}
                className="w-full p-3 border border-stone-300 focus:border-stone-900 focus:ring-0 transition-colors font-mono text-sm bg-stone-50"
                placeholder="••••••••"
              />
            </div>
            {error && <div className="text-red-600 text-xs flex items-center gap-2"><AlertCircle size={12} />{error}</div>}
            <button type="submit" className="w-full bg-stone-900 text-white py-3 px-4 hover:bg-stone-800 transition-colors uppercase tracking-widest text-xs font-semibold">
              Enviar Confirmación
            </button>
          </form>
        )}

        {step === 'ENTER_PASSWORD' && (
          <form onSubmit={handleLoginSubmit} className="space-y-6">
             <div>
              <label className="block text-xs uppercase tracking-widest text-stone-500 mb-2">Contraseña</label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full p-3 border border-stone-300 focus:border-stone-900 focus:ring-0 transition-colors font-mono text-sm bg-stone-50"
                placeholder="••••••••"
                autoFocus
              />
            </div>
            {error && <div className="text-red-600 text-xs flex items-center gap-2"><AlertCircle size={12} />{error}</div>}
            <button type="submit" className="w-full bg-stone-900 text-white py-3 px-4 hover:bg-stone-800 transition-colors uppercase tracking-widest text-xs font-semibold">
              Ingresar
            </button>
            <button type="button" onClick={() => { setStep('EMAIL'); setPassword(''); }} className="w-full text-stone-500 text-xs hover:text-stone-900 py-2">
              Cambiar usuario
            </button>
          </form>
        )}

        {step === 'EMAIL_SENT' && (
          <div className="space-y-6 text-center">
            <div className="bg-stone-50 p-6 border border-stone-100">
               <p className="text-sm text-stone-600 mb-4">
                 Para completar el registro, haga clic en el enlace que enviamos a su correo.
               </p>
               <div className="text-xs text-stone-400 font-mono mb-6">
                 (Simulación: El sistema no envía correos reales)
               </div>
               <button 
                onClick={simulateEmailVerification}
                className="w-full bg-blue-600 text-white py-3 px-4 hover:bg-blue-700 transition-colors font-medium text-sm rounded flex items-center justify-center gap-2 shadow-sm"
               >
                 <Mail size={16} /> Simular Entrada desde Correo
               </button>
            </div>
            <p className="text-xs text-stone-400">
              ¿No recibió el correo? Revise su carpeta de spam.
            </p>
          </div>
        )}
      </div>
    </div>
  );
};

