  score: number;
  description: string;
}

export interface RubricItem {
  id: string;
  title: string;
  description?: string;
  levels: RubricLevel[]; // 0 to 5
  minWeightConfig: number; // Set by admin (percentage)
  maxWeightConfig: number; // Set by admin (percentage)
}

