        items: cat.items.map(item => {
          if (item.id !== itemId) return item;
          return {
            ...item,
            [field === 'min' ? 'minWeightConfig' : 'maxWeightConfig']: value
          };
        })
      };
    });
    setLocalRubric(newRubric);
